const box = document.querySelector("#target");
box.textContent = "نص جديد وضعه JavaScript";
box.style.backgroundColor = "#ddd6fe";
box.style.padding = "10px";
box.style.borderRadius = "8px";

const alertBox = document.querySelector("#alert");
alertBox.classList.add("active");
console.log(alertBox.classList.contains("active")); // true

document.querySelector("#btn").addEventListener("click", () => {
  alertBox.classList.toggle("active");
});

const list = document.querySelector("#list");

const newItem = document.createElement("li");
newItem.textContent = "عنصر أنشأه JavaScript";
newItem.style.color = "green";
list.append(newItem);

const topItem = document.createElement("li");
topItem.textContent = "وأنا أضفت في المقدمة";
list.prepend(topItem);
